SELECT users.username, accounts.account_name 
FROM users 
JOIN accounts ON users.user_id = accounts.user_id;

SELECT AVG(account_balance) AS AverageBalance
FROM accounts
WHERE user_id = 123;

SELECT users.username, reminders.reminder_date, reminders.reminder_message
FROM users
JOIN reminders ON users.user_id = reminders.user_id;

SELECT AVG(account_count) 
FROM (
  SELECT user_id, COUNT(*) as account_count 
  FROM accounts 
  GROUP BY user_id
);
